  background-color: #3e8e41; /* Darker blue on hover */
}
```
JavaScript Code:
```javascript
// Get the modal and button elements
const modal = document.querySelector('.chat-modal');
const modalButton = document.querySelector('.chat-modal-btn');

// Add an event listener to the button
modalButton.addEventListener('click', function() {
  // Show the modal
  modal.style.display = 'block';

  // Get the messages from the database
  fetch('https://example.com/messages')
   .then(response => response.json())
   .then(data => {
      // Create the modal content
      const messages = data.messages.map(message => {
        const botMessage = message.botMessage;
        const humanMessage = message.humanMessage;
        return (`${botMessage} ${humanMessage}`);
      });

      // Update the modal content with the new messages
      modal.querySelector('.messages').innerHTML = messages.join('');
    });
});

// Hide the modal when the button is clicked again
modalButton.addEventListener('click', function() {
  modal.style.display = 'none';
});
```
This code creates a simple chat modal with a button to open it. When the button is clicked, it makes a request to a server for the messages and updates the modal content with the new messages. The messages are displayed in a flex container with equal width and height, and a dark gray background for the human messages. The bot messages have a light gray background.

You can replace the `fetch` request with your own API or database call to retrieve the messages.

